const input = $('When Executed by Another Workflow').first().json || {};

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

function slugify(value) {
  return toText(value).toLowerCase().replace(/[^a-z0-9_-]+/g, '-').replace(/^-+|-+$/g, '');
}

function hasNonEmptyValue(value) {
  if (Array.isArray(value)) return value.some((item) => hasNonEmptyValue(item));
  if (value && typeof value === 'object') return Object.values(value).some((item) => hasNonEmptyValue(item));
  return toText(value) !== '';
}

function hasNonEmptyPayload(payload) {
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) return false;
  const keys = Object.keys(payload);
  if (keys.length === 0) return false;
  return keys.some((key) => hasNonEmptyValue(payload[key]));
}

function inferMessageType(payload) {
  if (payload && Array.isArray(payload.cardsV2) && payload.cardsV2.length > 0) return 'cardsV2';
  if (payload && typeof payload.text === 'string' && payload.text.trim()) return 'text';
  return 'custom';
}

const rawMessages = Array.isArray(input.messages) ? input.messages : [];
const messages = rawMessages
  .filter((payload) => payload && typeof payload === 'object' && !Array.isArray(payload) && hasNonEmptyPayload(payload))
  .map((payload, requestIndex) => ({
    requestIndex,
    requestBody: payload,
    messageType: inferMessageType(payload),
  }));

const baseUrl = toText(input.webhookUrl || '');
const replyOption = encodeURIComponent(toText(input.messageReplyOption || 'REPLY_MESSAGE_FALLBACK_TO_NEW_THREAD') || 'REPLY_MESSAGE_FALLBACK_TO_NEW_THREAD');
const seed = slugify(input.threadSeed || 'jira-ai-agent-google-chat-delivery') || 'jira-ai-agent-google-chat-delivery';
const uniqueSuffix = Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 8);
const finalThreadKey = toText(input.threadKey || '') || (seed + '-' + uniqueSuffix).slice(0, 120);

let requestUrl = '';
let skipReason = '';
if (!baseUrl) {
  skipReason = 'ggChatWebhookUrl is not configured.';
} else if (messages.length === 0) {
  skipReason = 'No valid Google Chat message payloads were provided.';
} else {
  const separator = baseUrl.includes('?') ? '&' : '?';
  requestUrl = baseUrl + separator + 'threadKey=' + encodeURIComponent(finalThreadKey) + '&messageReplyOption=' + replyOption;
}

return {
  threadKey: finalThreadKey,
  requestUrl,
  messages,
  sendEnabled: Boolean(baseUrl) && messages.length > 0,
  skipReason,
};

const normalized = $('Normalize Delivery Request').first().json || {};

function asText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function normalizeEmail(value) {
  const email = asText(value).toLowerCase();
  return email.includes('@') ? email : '';
}

function extractHandleFromEmail(value) {
  const email = normalizeEmail(value);
  return email ? email.split('@')[0] : '';
}

function tokenDisplayText(token) {
  const upper = asText(token).replace(/^@/, '').toUpperCase();
  if (upper === 'LEAD') return '@Lead';
  if (upper === 'PM') return '@PM';
  if (upper === 'ASSIGNEE') return '@ASSIGNEE';
  if (upper === 'OWNER') return '@OWNER';
  if (upper === 'QCS') return '@QCS';
  return '@' + asText(token).replace(/^@/, '');
}

const memberRows = $input.all().map((item) => item?.json || {});
const directoryByKey = new Map();

function registerDirectoryKey(rawKey, entry) {
  const key = asText(rawKey).replace(/^@/, '').toLowerCase();
  if (!key || directoryByKey.has(key)) return;
  directoryByKey.set(key, entry);
}

for (const row of memberRows) {
  const normalizedRow = {};
  for (const [key, value] of Object.entries(row || {})) {
    normalizedRow[String(key || '').trim().toLowerCase()] = value;
  }

  const email = normalizeEmail(normalizedRow.email);
  const id = asText(normalizedRow.id);
  const name = asText(normalizedRow.name || normalizedRow.display_name || normalizedRow.displayname);
  const handle = asText(normalizedRow.handle || normalizedRow.username || normalizedRow.user_name || normalizedRow.jira_username) || extractHandleFromEmail(email);
  if (!id || !email) continue;

  const entry = {
    id,
    email,
    name,
    handle: asText(handle).replace(/^@/, '').toLowerCase(),
    mentionText: '<users/' + id + '>',
  };

  registerDirectoryKey(email, entry);
  registerDirectoryKey(entry.handle, entry);
  registerDirectoryKey(name, entry);
  registerDirectoryKey(normalizedRow.username, entry);
  registerDirectoryKey(normalizedRow.user_name, entry);
  registerDirectoryKey(normalizedRow.jira_username, entry);
  registerDirectoryKey(normalizedRow.display_name, entry);
  registerDirectoryKey(normalizedRow.displayname, entry);
}

function resolveMemberFromToken(token) {
  const key = asText(token).replace(/^@/, '').toLowerCase();
  if (!key) return null;
  return directoryByKey.get(key) || null;
}

function buildMentionFooter(occurrences) {
  const uniqueByMention = new Map();
  for (const occurrence of occurrences.sort((left, right) => left.offset - right.offset)) {
    if (!occurrence?.mentionText || uniqueByMention.has(occurrence.mentionText)) continue;
    uniqueByMention.set(occurrence.mentionText, occurrence);
  }

  const ordered = Array.from(uniqueByMention.values());
  return {
    mentionTail: ordered.map((item) => item.mentionText).join(' '),
    resolvedPeople: ordered.map((item, index) => ({
      token: item.token,
      handle: item.handle,
      mentionText: item.mentionText,
      displayName: item.displayName,
      firstOffset: item.offset,
      order: index,
    })),
    appendedMentionIds: ordered.map((item) => item.mentionText),
  };
}

function renderTextMentions(rawText) {
  const mentionOccurrences = [];
  const roleTokens = [];

  const renderedText = asText(rawText).replace(/(^|[\s(/])\*?@([A-Za-z0-9._-]{2,64})\*?\b/g, (full, prefix, rawToken, offset) => {
    const token = asText(rawToken);
    const upper = token.toUpperCase();
    if (!token) return full;

    if (['PM', 'LEAD', 'ASSIGNEE', 'OWNER', 'QCS'].includes(upper)) {
      roleTokens.push({ token: '@' + upper, offset });
      return full;
    }

    const member = resolveMemberFromToken(token);
    if (member?.mentionText) {
      const handle = asText(member.handle || token).replace(/^@/, '').toLowerCase();
      mentionOccurrences.push({
        token: '@' + token,
        handle,
        mentionText: member.mentionText,
        displayName: asText(member.name || member.email || handle),
        offset,
      });
      return full;
    }

    return full;
  });

  const footer = buildMentionFooter(mentionOccurrences);
  const finalText = footer.mentionTail ? renderedText + '\n' + footer.mentionTail : renderedText;

  return {
    text: finalText,
    mentionTail: footer.mentionTail,
    resolvedPeople: footer.resolvedPeople,
    roleTokens: roleTokens.sort((left, right) => left.offset - right.offset).map((item) => item.token),
    appendedMentionIds: footer.appendedMentionIds,
  };
}

const messages = asArray(normalized.messages).map((message, index) => {
  const requestBody = message?.requestBody && typeof message.requestBody === 'object' ? { ...message.requestBody } : null;
  const rendered = requestBody && typeof requestBody.text === 'string'
    ? renderTextMentions(requestBody.text)
    : null;

  return {
    ...message,
    requestBody: rendered ? { ...requestBody, text: rendered.text } : requestBody,
    mentionRender: rendered ? {
      messageIndex: index,
      mentionTail: rendered.mentionTail,
      resolvedPeople: rendered.resolvedPeople,
      roleTokens: rendered.roleTokens,
      appendedMentionIds: rendered.appendedMentionIds,
    } : {
      messageIndex: index,
      mentionTail: '',
      resolvedPeople: [],
      roleTokens: [],
      appendedMentionIds: [],
    },
  };
});

return {
  ...normalized,
  lineMentions: messages.map((message) => message.mentionRender),
  messages: messages.map((message) => {
    const clone = { ...message };
    delete clone.mentionRender;
    return clone;
  }),
};

const rendered = $('Render Mentioned Messages').first().json || {};
const messages = Array.isArray(rendered.messages) ? rendered.messages : [];
const requestUrl = String(rendered.requestUrl || '').trim();
const threadKey = String(rendered.threadKey || '').trim();

return messages.map((message, requestIndex) => ({
  json: {
    requestIndex,
    requestUrl,
    threadKey,
    ...message,
  },
}));

const normalized = $('Render Mentioned Messages').first().json || $('Normalize Delivery Request').first().json || {};

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

let deliveryResponses = [];
try {
  deliveryResponses = $('Send Google Chat Message').all().map((item) => item?.json || item || {});
} catch (error) {
  deliveryResponses = [];
}

const successCount = deliveryResponses.filter((item) => Number(item.statusCode || 0) >= 200 && Number(item.statusCode || 0) < 300).length;
const failureCount = deliveryResponses.filter((item) => Number(item.statusCode || 0) > 0 && (Number(item.statusCode || 0) < 200 || Number(item.statusCode || 0) >= 300)).length;
const sentCount = deliveryResponses.length;
const skipped = !Boolean(normalized.sendEnabled);
const status = skipped ? 'skipped' : (failureCount > 0 ? (successCount > 0 ? 'partial' : 'error') : 'sent');
const resultText = skipped
  ? (toText(normalized.skipReason) || 'Google Chat delivery skipped.')
  : 'Sent ' + sentCount + ' Google Chat message(s) to thread ' + toText(normalized.threadKey || '') + '.';

return {
  toolName: 'googleChatBatchDelivery',
  status,
  success: status === 'sent' || status === 'partial',
  threadKey: toText(normalized.threadKey || ''),
  sentCount,
  successCount,
  failureCount,
  skipReason: toText(normalized.skipReason || ''),
  resultText,
};
